const lead = $('Normalizar Lead').first().json;
const reply = $('AI Agent Aura').first().json;

const instanceName = String(lead.instanceName || '').trim();
const number = String(lead.waNumber || '').trim();
const text = String(reply.output || '').trim();

if (!instanceName) {
  throw new Error('Preparar Resposta WhatsApp: instanceName vazio');
}

if (!number) {
  throw new Error('Preparar Resposta WhatsApp: number vazio');
}

if (!text) {
  throw new Error('Preparar Resposta WhatsApp: text vazio');
}

return [{
  json: {
    instanceName,
    number,
    text
  }
}];

const msg = $('Normalizar Mensagem').first().json;
const messageText = String(msg.fallbackText || '').trim();
if (!messageText) {
  throw new Error('Preparar Texto Original: mensagem vazia');
}
return [{ json: { ...msg, messageText } }];

const msg = $('Normalizar Mensagem').first().json;
const analysis = String((($json.content?.parts) || []).map((part) => part.text).filter(Boolean).join('\n')).trim();
const caption = String(msg.rawText || '').trim();
const interpretation = analysis || 'Imagem recebida, mas a analise retornou vazia.';
const messageText = caption
  ? `O cliente enviou uma imagem com legenda: "${caption}". Interpretacao da imagem: ${interpretation}`
  : `O cliente enviou uma imagem. Interpretacao da imagem: ${interpretation}`;
return [{ json: { ...msg, messageText } }];

const msg = $('Normalizar Mensagem').first().json;
const transcript = String((($json.content?.parts) || []).map((part) => part.text).filter(Boolean).join('\n')).trim();
const finalTranscript = transcript || 'Audio recebido, mas a transcricao retornou vazia.';
const messageText = `O cliente enviou um audio. Transcricao: ${finalTranscript}`;
return [{ json: { ...msg, messageText } }];

const row = $json && typeof $json === 'object' ? $json : {};
const rateData = $('Consolidar Tarifas Aura').first().json;

const parsedCheckIn = String(rateData.parsedCheckIn || '').trim();
const parsedCheckOut = String(rateData.parsedCheckOut || '').trim();
const requestedRoomType = String(rateData.requestedRoomType || '').trim() || null;
const apiBaseUrl = String(row.api_base_url || 'https://pms.hospedin.com/api/v2').trim().replace(/\/$/, '');
const accountId = String(row.account_id || '').trim();
const enabled = row.enabled === true;
const timeoutMsRaw = Number(row.timeout_ms || 10000);
const timeoutMs = Number.isFinite(timeoutMsRaw) && timeoutMsRaw >= 1000 ? timeoutMsRaw : 10000;
const fallbackMessage = String(row.fallback_message || 'No momento nao consegui confirmar a disponibilidade em tempo real. Posso seguir com a cotacao e a equipe confirma manualmente.').trim();
const hasValidStay = Boolean(parsedCheckIn && parsedCheckOut);
const shouldConsult = Boolean(enabled && hasValidStay && accountId);

let skipReason = null;
if (!enabled) skipReason = 'integration_disabled';
else if (!hasValidStay) skipReason = 'missing_dates';
else if (!accountId) skipReason = 'missing_account_id';

let defaultAvailabilityContext = '';
if (!enabled) {
  defaultAvailabilityContext = `DISPONIBILIDADE HOSPEDIN: integracao desativada. ${fallbackMessage}`;
} else if (!hasValidStay) {
  defaultAvailabilityContext = 'DISPONIBILIDADE HOSPEDIN: ainda nao foi possivel consultar porque faltam check-in e check-out validos.';
} else if (!accountId) {
  defaultAvailabilityContext = `DISPONIBILIDADE HOSPEDIN: integracao configurada sem account_id. ${fallbackMessage}`;
}

return [{
  json: {
    enabled,
    apiBaseUrl,
    accountId,
    timeoutMs,
    fallbackMessage,
    parsedCheckIn,
    parsedCheckOut,
    requestedRoomType,
    shouldConsult,
    skipReason,
    defaultAvailabilityContext,
  },
}];

const settings = $('Resolver Consulta Hospedin').first().json;
const mappings = items
  .map((item) => item.json || {})
  .filter((row) => Object.keys(row).length > 0)
  .filter((row) => row.active !== false);

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const parseBrDateToIso = (value) => {
  const text = String(value || '').trim();
  const match = text.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!match) return null;
  return `${match[3]}-${match[2]}-${match[1]}`;
};

const formatStatus = (status, detail) => `DISPONIBILIDADE HOSPEDIN: ${status}.${detail ? ` ${detail}` : ''}`.trim();

if (!settings.shouldConsult) {
  return [{
    json: {
      availabilityContext: settings.defaultAvailabilityContext || formatStatus('consulta nao executada', settings.fallbackMessage),
      availabilityLive: false,
      availabilityStatus: settings.skipReason || 'skipped',
      checkedPlaceTypes: 0,
      consultedRoomType: settings.requestedRoomType || null,
      hospedinApiStatus: null,
    },
  }];
}

const email = String(process.env.HOSPEDIN_API_EMAIL || '').trim();
const password = String(process.env.HOSPEDIN_API_PASSWORD || '').trim();
if (!email || !password) {
  return [{
    json: {
      availabilityContext: formatStatus('credenciais ausentes no ambiente do n8n', settings.fallbackMessage),
      availabilityLive: false,
      availabilityStatus: 'credentials_missing',
      checkedPlaceTypes: 0,
      consultedRoomType: settings.requestedRoomType || null,
      hospedinApiStatus: null,
    },
  }];
}

const requestedRoomType = String(settings.requestedRoomType || '').trim();
const selectedMappings = mappings.filter((row) => {
  const hasPlaceType = String(row.place_type_id || '').trim();
  if (!hasPlaceType) return false;
  if (!requestedRoomType) return true;
  return normalize(row.room_type) === normalize(requestedRoomType);
});

if (!selectedMappings.length) {
  return [{
    json: {
      availabilityContext: formatStatus('mapeamento de acomodacao ausente', settings.fallbackMessage),
      availabilityLive: false,
      availabilityStatus: 'mapping_missing',
      checkedPlaceTypes: 0,
      consultedRoomType: requestedRoomType || null,
      hospedinApiStatus: null,
    },
  }];
}

const beginDate = parseBrDateToIso(settings.parsedCheckIn);
const endDate = parseBrDateToIso(settings.parsedCheckOut);
if (!beginDate || !endDate) {
  return [{
    json: {
      availabilityContext: formatStatus('datas invalidas para consulta', settings.fallbackMessage),
      availabilityLive: false,
      availabilityStatus: 'invalid_dates',
      checkedPlaceTypes: 0,
      consultedRoomType: requestedRoomType || null,
      hospedinApiStatus: null,
    },
  }];
}

const controller = new AbortController();
const timeout = setTimeout(() => controller.abort(), Number(settings.timeoutMs || 10000));

try {
  const authResponse = await fetch(`${settings.apiBaseUrl}/authentication/sessions`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
    body: JSON.stringify({ email, password }),
    signal: controller.signal,
  });

  if (!authResponse.ok) {
    const errorText = (await authResponse.text().catch(() => '')).trim();
    return [{
      json: {
        availabilityContext: formatStatus(`autenticacao indisponivel (HTTP ${authResponse.status})`, errorText || settings.fallbackMessage),
        availabilityLive: false,
        availabilityStatus: 'auth_error',
        checkedPlaceTypes: 0,
        consultedRoomType: requestedRoomType || null,
        hospedinApiStatus: authResponse.status,
      },
    }];
  }

  const authJson = await authResponse.json().catch(() => ({}));
  const token = String(authJson.token || '').trim();
  if (!token) {
    return [{
      json: {
        availabilityContext: formatStatus('token de autenticacao ausente', settings.fallbackMessage),
        availabilityLive: false,
        availabilityStatus: 'auth_token_missing',
        checkedPlaceTypes: 0,
        consultedRoomType: requestedRoomType || null,
        hospedinApiStatus: authResponse.status,
      },
    }];
  }

  const headers = { Authorization: `Bearer ${token}`, Accept: 'application/json' };
  const summaries = [];
  let successCount = 0;
  let lastStatus = 200;

  for (const mapping of selectedMappings) {
    const roomType = String(mapping.room_type || '').trim() || 'Acomodacao sem nome';
    const placeTypeId = String(mapping.place_type_id || '').trim();
    const url = `${settings.apiBaseUrl}/${encodeURIComponent(settings.accountId)}/place_types/${encodeURIComponent(placeTypeId)}/rates_and_availabilities?begin_date=${encodeURIComponent(beginDate)}&end_date=${encodeURIComponent(endDate)}`;
    const response = await fetch(url, { method: 'GET', headers, signal: controller.signal });
    lastStatus = response.status;

    if (!response.ok) {
      summaries.push(`- ${roomType}: nao foi possivel confirmar na Hospedin agora (HTTP ${response.status}).`);
      continue;
    }

    successCount += 1;
    const payload = await response.json().catch(() => []);
    const rows = Array.isArray(payload) ? payload : [];
    const stayRows = rows.filter((row) => {
      const date = String(row.date || '').trim();
      return date >= beginDate && date < endDate;
    });

    if (!stayRows.length) {
      summaries.push(`- ${roomType}: a Hospedin nao retornou dias suficientes para o periodo consultado.`);
      continue;
    }

    const availabilities = stayRows.map((row) => Number(row.availability || 0)).filter((value) => Number.isFinite(value));
    const minAvailability = availabilities.length ? Math.min(...availabilities) : 0;
    const isAvailable = stayRows.every((row) => Number(row.availability || 0) > 0);

    if (isAvailable) {
      summaries.push(`- ${roomType}: disponivel em todo o periodo consultado. Menor disponibilidade diaria encontrada: ${minAvailability} unidade(s).`);
    } else {
      summaries.push(`- ${roomType}: indisponivel em pelo menos uma das datas consultadas.`);
    }
  }

  const availabilityContext = successCount
    ? `DISPONIBILIDADE HOSPEDIN PARA ${settings.parsedCheckIn} a ${settings.parsedCheckOut}:\n${summaries.join('\n')}`
    : formatStatus('sem resposta valida da Hospedin', settings.fallbackMessage);

  return [{
    json: {
      availabilityContext,
      availabilityLive: successCount > 0,
      availabilityStatus: successCount > 0 ? 'ok' : 'no_valid_response',
      checkedPlaceTypes: selectedMappings.length,
      consultedRoomType: requestedRoomType || null,
      hospedinApiStatus: lastStatus,
    },
  }];
} catch (error) {
  const reason = error && error.name === 'AbortError' ? 'timeout na consulta da Hospedin' : 'falha ao consultar a Hospedin';
  const detail = error && error.message ? String(error.message) : settings.fallbackMessage;
  return [{
    json: {
      availabilityContext: formatStatus(reason, detail || settings.fallbackMessage),
      availabilityLive: false,
      availabilityStatus: error && error.name === 'AbortError' ? 'timeout' : 'request_failed',
      checkedPlaceTypes: selectedMappings.length,
      consultedRoomType: requestedRoomType || null,
      hospedinApiStatus: null,
    },
  }];
} finally {
  clearTimeout(timeout);
}
